def assess_risk_level(patient_id: str, symptoms: str, vital_signs: str = None) -> dict:
    emergency_keywords = ['chest pain', 'shortness of breath', 'syncope', 'severe headache']
    high_risk_keywords = ['severe', 'sudden', 'radiating']
    symptoms_lower = symptoms.lower()
    if any(kw in symptoms_lower for kw in emergency_keywords):
        return {
            'patient_id': patient_id,
            'risk_level': 'emergency',
            'recommendation': 'Immediate emergency department referral',
            'time_frame': 'within 15 minutes',
            'red_flags': [symptoms]
        }
    elif any(kw in symptoms_lower for kw in high_risk_keywords):
        return {
            'patient_id': patient_id,
            'risk_level': 'high',
            'recommendation': 'Urgent specialist consultation required',
            'time_frame': 'within 24 hours',
            'red_flags': ['Severe symptoms present']
        }
    return {
        'patient_id': patient_id,
        'risk_level': 'Medium',
        'recommendation': 'Monitor blood pressure q4h',
        'time_frame': 'within 48 hours',
        'red_flags': [],
        'icd10_hint': 'I10 (Essential hypertension)'
    }

def retrieve_clinical_guideline(condition: str, specialty: str, guideline_aspect: str) -> dict:
    guidelines = {
        'hypertension': {
            'cardiology': {
                'treatment': {
                    'snippet': 'Amlodipine 5-10mg qd for CKD stage 3 patients, target BP <130/80 mmHg',
                    'evidence_level': 'Level A',
                    'guideline_version': '2025 ESC Hypertension Guideline'
                },
                'diagnosis': {
                    'snippet': 'Diagnose hypertension if BP >=130/80 mmHg on 2+ occasions',
                    'evidence_level': 'Level B',
                    'guideline_version': '2025 ESC Hypertension Guideline'
                }
            },
            'nephrology': {
                'treatment': {
                    'snippet': 'ACEi or ARB first-line for hypertension with CKD, monitor eGFR and K+',
                    'evidence_level': 'Level A',
                    'guideline_version': 'KDIGO 2024 Hypertension in CKD Guideline'
                }
            }
        }
    }
    if condition.lower() in guidelines and specialty in guidelines[condition.lower()]:
        guideline_data = guidelines[condition.lower()][specialty].get(guideline_aspect, {})
        if guideline_data:
            return {
                'condition': condition,
                'specialty': specialty,
                'guideline_aspect': guideline_aspect,
                'recommendation': guideline_data['snippet'],
                'evidence_level': guideline_data['evidence_level'],
                'guideline_source': guideline_data['guideline_version']
            }
    return {
        'condition': condition,
        'specialty': specialty,
        'guideline_aspect': guideline_aspect,
        'recommendation': 'No specific guideline found',
        'evidence_level': 'N/A',
        'guideline_source': 'N/A'
    }
